#include<bits/stdc++.h>
using namespace std;
bool a[105];
int b[105][105],d[105],n,m,ans;
void f(int j){
	if(a[j]==0)return;
	for(int i=1;i<=d[j];i++){
		a[j]&=a[b[j][i]];
	}return;
}
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>d[i];
		for(int j=1;j<=d[i];j++){
			cin>>b[i][j];
		}
	}cin>>m;
	for(int i=1;i<=m;i++){
		ans=0;
		for(int j=1;j<=n;j++){
			cin>>a[j];
			f(j);
			ans+=a[j];
		}cout<<ans<<'\n';
	}
	return false;
}
